solution: ```class Solution:
    def findMinimumOperations(self, s1: str, s2: str, s3: str) -> int:
        l1, l2, l3 = len(s1), len(s2), len(s3)
        min_len = min(l1, l2, l3)
        for i in range(min_len + 1):
            if i == min_len:
                if s1[:i] == s2[:i] == s3[:i]:
                    return (l1 - i) + (l2 - i) + (l3 - i)
                else:
                    return -1
            if not (s1[i] == s2[i] == s3[i]):
                if i == 0:
                    return -1
                return (l1 - i) + (l2 - i) + (l3 - i)
        return -1
